class Solution:
    def longestBalanced(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(i, n):
                ev = set()
                od = set()
                for k in range(i, j + 1):
                    if nums[k] % 2 == 0:
                        ev.add(nums[k])
                    else:
                        od.add(nums[k])
                if len(ev) == len(od):
                    best = max(best, j - i + 1)
        return best

