var longestBalanced = function(nums) {
    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        const ev = new Set();
        const od = new Set();
        for (let j = i; j < n; j++) {
            const v = nums[j];
            if (v % 2 === 0) ev.add(v); else od.add(v);
            if (ev.size === od.size) best = Math.max(best, j - i + 1);
        }
    }
    return best;
};
